  assert CountInt(result, 0) == y;

  // Feasibility
  assert FeasibleCounts(gcn, gcz, gcr, gco, gce, x, y);

  // Optimality
  forall a: nat, b: nat | FeasibleCounts(gcn, gcz, gcr, gco, gce, a, b)
    ensures BinaryGeq(x, y, a, b)
