      n := n + 1;
    }
  }

  assert z == CountChar(s, 'z') && e == CountChar(s, 'e') && r == CountChar(s, 'r') && o == CountChar(s, 'o') && n == CountChar(s, 'n');

  // Save original character counts
  ghost var gcn := n;
  ghost var gcz := z;
  ghost var gcr := r;
  ghost var gco := o;
  ghost var gce := e;

  // Compute x = min(o, n, e) — maximum number of "one"s
  var x := o;
  if n < x { x := n; }
  if e < x { x := e; }

  assert x <= gco && x <= gcn && x <= gce;
  assert x == gco || x == gcn || x == gce;

  // Subtract letters used by "one"s
  o := o - x;
  n := n - x;
  e := e - x;

  // Compute y = min(z, e, r, o) — maximum number of "zero"s from remaining
  var y := z;
  if e < y { y := e; }
  if r < y { y := r; }
  if o < y { y := o; }

  assert y <= gcz && y <= gce - x && y <= gcr && y <= gco - x;
  assert y == gcz || y == gce - x || y == gcr || y == gco - x;

