  CountIntOnesSeq(x);
  CountIntZerosSeq(y);
  CountIntConcat(seq(x, (i: nat) => 1), seq(y, (i: nat) => 0), 1);
  CountIntConcat(seq(x, (i: nat) => 1), seq(y, (i: nat) => 0), 0);

