  assert xp <= x;

  if xp == 0 {
    // BinaryGeq(x, y, 0, yp) is true by definition
  } else {
    // Both x > 0, xp > 0. Need x+y >= xp+yp (then BinaryGeq follows since x >= xp)
    if y == co - x {
      assert x + y == co;
      assert xp + yp <= co;
    } else if y == ce - x {
      assert x + y == ce;
      assert xp + yp <= ce;
    } else if y == cz {
      assert yp <= cz;
      assert yp <= y;
      assert xp + yp <= x + y;
    } else {
      assert y == cr;
      assert yp <= cr;
      assert yp <= y;
      assert xp + yp <= x + y;
    }
  }
}

