    CountCharStep(s, i, 'r');
    CountCharStep(s, i, 'o');
    CountCharStep(s, i, 'n');
    if s[i] == 'z' {
      z := z + 1;
    } else if s[i] == 'e' {
      e := e + 1;
    } else if s[i] == 'r' {
      r := r + 1;
    } else if s[i] == 'o' {
      o := o + 1;
    } else {
      assert s[i] == 'n';
      n := n + 1;
    }
  }

  assert Feasible(s, x, y);

  // Save original character counts
  ghost var gcn := n;
  ghost var gcz := z;
  ghost var gcr := r;
  ghost var gco := o;
  ghost var gce := e;

  // Compute x = min(o, n, e) — maximum number of "one"s
  var x := o;
  if n < x { x := n; }
  if e < x { x := e; }

  assert x <= gco && x <= gcn && x <= gce;
  assert x == gco || x == gcn || x == gce;

  // Subtract letters used by "one"s
  o := o - x;
  n := n - x;
  e := e - x;

  // Compute y = min(z, e, r, o) — maximum number of "zero"s from remaining
  var y := z;
  if e < y { y := e; }
  if r < y { y := r; }
  if o < y { y := o; }

